#[cfg(test)]
mod tests {
    use super::*;
    use crate::MeasurementSingle;

    fn dummy_source(path: &str) -> MeasurementSource {
        MeasurementSource::Single(MeasurementSingle {
            measurement: crate::read::MeasurementRef::Path(std::path::PathBuf::from(path)),
            speaker_name: None,
        })
    }

    #[test]
    fn json_roundtrip() {
        let group = SupportingSourceGroup {
            name: "Left Main + Support".to_string(),
            speaker_name: Some("KEF R3 + Genelec 8030".to_string()),
            primary: dummy_source("measurements/left_primary.csv"),
            support: dummy_source("measurements/left_support.csv"),
            supporting_source: SupportingSourceConfig::default(),
        };
        let json = serde_json::to_string(&group).unwrap();
        let back: SupportingSourceGroup = serde_json::from_str(&json).unwrap();
        assert_eq!(back.name, group.name);
        assert_eq!(back.speaker_name, group.speaker_name);
    }

    #[test]
    fn resolve_paths_updates_relative_paths() {
        let mut group = SupportingSourceGroup {
            name: "test".to_string(),
            speaker_name: None,
            primary: dummy_source("primary.csv"),
            support: dummy_source("support.csv"),
            supporting_source: SupportingSourceConfig::default(),
        };
        let base = std::path::PathBuf::from("/tmp/base");
        group.resolve_paths(&base);
        match &group.primary {
            MeasurementSource::Single(s) => {
                assert_eq!(s.measurement.path().unwrap(), &base.join("primary.csv"));
            }
            _ => panic!("expected Single source"),
        }
        match &group.support {
            MeasurementSource::Single(s) => {
                assert_eq!(s.measurement.path().unwrap(), &base.join("support.csv"));
            }
            _ => panic!("expected Single source"),
        }
    }
}
